ARCHIVOS["Backend/cultivos/app/services/cultivo_service.py"] = '# ==============================================================\n# modulo_02_cultivos / app/services/cultivo_service.py\n# Logica de negocio - Cultivos, Lotes y Sensores\n#\n# Reglas implementadas:\n#   RN-02  Todo lote debe tener trazabilidad completa antes\n#          de pasar al estado \'vendido\'\n#   RNF-05 Integridad - eliminacion logica (no fisica)\n#   RNF-06 Soporte para nuevos sensores IoT sin cambios de schema\n#\n# Casos de prueba cubiertos:\n#   CP-03  Registro cultivo\n#   CP-04  Registro lote\n# ==============================================================\n\nimport secrets\nimport logging\nfrom typing import List, Optional\n\nfrom fastapi import HTTPException, status\nfrom sqlalchemy import func, text\nfrom sqlalchemy.orm import Session\n\nfrom app.models.cultivo import Cultivo, Lote, Sensor\nfrom app.schemas.cultivo import (\n    CultivoCreate, CultivoUpdate,\n    LoteCreate, LoteUpdate,\n    SensorCreate,\n    ResumenCultivoResponse,\n)\n\nlogger = logging.getLogger(__name__)\n\n\n# ==============================================================\n# TRANSICIONES VALIDAS DE ESTADO\n# Implementa las reglas del diagrama de estados oficial\n# ==============================================================\n\nTRANSICIONES_CULTIVO = {\n    "creado":                  {"en_seguimiento", "eliminado"},\n    "en_seguimiento":          {"con_problema_detectado", "finalizado", "eliminado"},\n    "con_problema_detectado":  {"tratamiento_aplicado", "en_seguimiento"},\n    "tratamiento_aplicado":    {"en_seguimiento", "finalizado"},\n    "finalizado":              set(),\n    "eliminado":               set(),\n}\n\nTRANSICIONES_LOTE = {\n    "registrado":   {"disponible", "eliminado"},\n    "disponible":   {"en_analisis", "eliminado"},\n    "en_analisis":  {"aprobado", "con_problema"},\n    "aprobado":     {"vendido"},\n    "con_problema": {"en_analisis", "eliminado"},\n    "vendido":      set(),\n    "eliminado":    set(),\n}\n\n\nclass CultivoService:\n    """Servicio principal para gestion de cultivos y lotes."""\n\n    def __init__(self, db: Session):\n        self.db = db\n\n    # ----------------------------------------------------------\n    # CULTIVOS - RF-03\n    # ----------------------------------------------------------\n\n    def crear_cultivo(\n        self, datos: CultivoCreate, usuario_id: int\n    ) -> Cultivo:\n        """\n        CP-03: registra un nuevo cultivo en estado \'creado\'.\n        Vincula el cultivo al usuario autenticado.\n        """\n        cultivo = Cultivo(\n            nombre_cultivo=datos.nombre_cultivo,\n            ubicacion=datos.ubicacion,\n            area_hectareas=datos.area_hectareas,\n            variedad_cafe=datos.variedad_cafe,\n            fecha_siembra=datos.fecha_siembra,\n            observaciones=datos.observaciones,\n            estado="creado",\n            id_usuario=usuario_id,\n        )\n        self.db.add(cultivo)\n        self.db.commit()\n        self.db.refresh(cultivo)\n        logger.info(\n            f"Cultivo creado: id={cultivo.id_cultivo} "\n            f"nombre=\'{cultivo.nombre_cultivo}\' usuario={usuario_id}"\n        )\n        return cultivo\n\n    def listar_cultivos(self, usuario_id: int) -> List[Cultivo]:\n        """\n        Retorna los cultivos activos del usuario autenticado.\n        No incluye cultivos en estado \'eliminado\'.\n        """\n        return (\n            self.db.query(Cultivo)\n            .filter(\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .order_by(Cultivo.fecha_registro.desc())\n            .all()\n        )\n\n    def obtener_cultivo(\n        self, cultivo_id: int, usuario_id: int\n    ) -> Cultivo:\n        """\n        Retorna un cultivo verificando la propiedad del usuario.\n        Lanza HTTP 404 si no existe o no pertenece al usuario.\n        """\n        cultivo = (\n            self.db.query(Cultivo)\n            .filter(\n                Cultivo.id_cultivo == cultivo_id,\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .first()\n        )\n        if not cultivo:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=(\n                    f"Cultivo con id={cultivo_id} no encontrado "\n                    "o no tiene acceso a este recurso"\n                ),\n            )\n        return cultivo\n\n    def actualizar_cultivo(\n        self, cultivo_id: int, datos: CultivoUpdate, usuario_id: int\n    ) -> Cultivo:\n        """\n        Actualiza los datos de un cultivo.\n        Valida la transicion de estado contra el diagrama de estados oficial.\n        """\n        cultivo = self.obtener_cultivo(cultivo_id, usuario_id)\n\n        if datos.estado:\n            self._validar_transicion_cultivo(cultivo.estado, datos.estado)  # N-001 FIX: 2 args\n\n        campos = datos.model_dump(exclude_unset=True)\n        for campo, valor in campos.items():\n            setattr(cultivo, campo, valor)\n\n        self.db.commit()\n        self.db.refresh(cultivo)\n        logger.info(\n            f"Cultivo actualizado: id={cultivo_id} "\n            f"estado=\'{cultivo.estado}\'"\n        )\n        return cultivo\n\n    def eliminar_cultivo(\n        self, cultivo_id: int, usuario_id: int\n    ) -> None:\n        """\n        RNF-05: eliminacion logica. El cultivo pasa a estado \'eliminado\'.\n        No se borra el registro fisico de la base de datos.\n        """\n        cultivo = self.obtener_cultivo(cultivo_id, usuario_id)\n        cultivo.estado = "eliminado"\n        self.db.commit()\n        logger.info(f"Cultivo eliminado (logico): id={cultivo_id}")\n\n    def resumen_dashboard(self, usuario_id: int) -> ResumenCultivoResponse:\n        """\n        Genera el resumen estadistico para el panel principal\n        del Caficultor con una sola consulta agregada.\n        """\n        cultivos_activos = (\n            self.db.query(func.count(Cultivo.id_cultivo))\n            .filter(\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .scalar() or 0\n        )\n\n        area_total = (\n            self.db.query(func.sum(Cultivo.area_hectareas))\n            .filter(\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .scalar() or 0.0\n        )\n\n        # Subquery para obtener lotes de los cultivos del usuario\n        ids_cultivos = (\n            self.db.query(Cultivo.id_cultivo)\n            .filter(Cultivo.id_usuario == usuario_id)\n            .subquery()\n        )\n\n        total_lotes = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(Lote.id_cultivo.in_(ids_cultivos))\n            .scalar() or 0\n        )\n\n        lotes_en_proceso = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(\n                Lote.id_cultivo.in_(ids_cultivos),\n                Lote.estado_lote.in_(["registrado", "disponible", "en_analisis"]),\n            )\n            .scalar() or 0\n        )\n\n        lotes_vendidos = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(\n                Lote.id_cultivo.in_(ids_cultivos),\n                Lote.estado_lote == "vendido",\n            )\n            .scalar() or 0\n        )\n\n        lotes_con_problema = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(\n                Lote.id_cultivo.in_(ids_cultivos),\n                Lote.estado_lote == "con_problema",\n            )\n            .scalar() or 0\n        )\n\n        return ResumenCultivoResponse(\n            total_cultivos_activos=cultivos_activos,\n            total_lotes=total_lotes,\n            lotes_en_proceso=lotes_en_proceso,\n            lotes_vendidos=lotes_vendidos,\n            lotes_con_problema=lotes_con_problema,\n            area_total_hectareas=float(area_total),\n        )\n\n    # ----------------------------------------------------------\n    # LOTES - RF-04\n    # ----------------------------------------------------------\n\n    def crear_lote(\n        self, cultivo_id: int, datos: LoteCreate, usuario_id: int\n    ) -> Lote:\n        """\n        CP-04: registra un nuevo lote en estado \'registrado\'.\n        Genera automaticamente el codigo QR para consulta publica (RF-15).\n        Verifica que el usuario sea propietario del cultivo.\n        """\n        self.obtener_cultivo(cultivo_id, usuario_id)\n\n        existente = self.db.query(Lote).filter(\n            Lote.codigo_lote == datos.codigo_lote\n        ).first()\n        if existente:\n            raise HTTPException(\n                status_code=status.HTTP_409_CONFLICT,\n                detail=(\n                    f"Ya existe un lote con el codigo \'{datos.codigo_lote}\'. "\n                    "Use un codigo unico para este lote."\n                ),\n            )\n\n        # Genera token URL-safe de 48 chars para el QR\n        codigo_qr = secrets.token_urlsafe(36)\n\n        lote = Lote(\n            codigo_lote=datos.codigo_lote,\n            codigo_qr=codigo_qr,\n            fecha_cosecha=datos.fecha_cosecha,\n            cantidad_kg=datos.cantidad_kg,\n            observaciones=datos.observaciones,\n            estado_lote="registrado",\n            id_cultivo=cultivo_id,\n        )\n        self.db.add(lote)\n        self.db.commit()\n        self.db.refresh(lote)\n        logger.info(\n            f"Lote creado: id={lote.id_lote} "\n            f"codigo=\'{lote.codigo_lote}\' cultivo={cultivo_id}"\n        )\n        return lote\n\n    def listar_lotes(\n        self, cultivo_id: int, usuario_id: int\n    ) -> List[Lote]:\n        """Retorna los lotes del cultivo que pertenece al usuario."""\n        self.obtener_cultivo(cultivo_id, usuario_id)\n        return (\n            self.db.query(Lote)\n            .filter(\n                Lote.id_cultivo == cultivo_id,\n                Lote.estado_lote != "eliminado",\n            )\n            .order_by(Lote.fecha_registro.desc())\n            .all()\n        )\n\n    def obtener_lote(\n        self, lote_id: int, usuario_id: int\n    ) -> Lote:\n        """Obtiene un lote verificando la cadena de propiedad usuario-cultivo."""\n        lote = (\n            self.db.query(Lote)\n            .join(Cultivo)\n            .filter(\n                Lote.id_lote == lote_id,\n                Cultivo.id_usuario == usuario_id,\n                Lote.estado_lote != "eliminado",\n            )\n            .first()\n        )\n        if not lote:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=f"Lote con id={lote_id} no encontrado o sin acceso",\n            )\n        return lote\n\n    def actualizar_lote(\n        self, lote_id: int, datos: LoteUpdate, usuario_id: int\n    ) -> Lote:\n        """\n        Actualiza el estado u observaciones de un lote.\n        RN-02: bloquea el paso a \'vendido\' si no hay trazabilidad completa.\n        Valida transiciones segun el diagrama de estados del Lote.\n        """\n        lote = self.obtener_lote(lote_id, usuario_id)\n\n        if datos.estado_lote:\n            self._validar_transicion_lote(lote.estado_lote, datos.estado_lote)\n\n            if datos.estado_lote == "vendido":\n                self._verificar_trazabilidad_rn02(lote_id)\n\n            lote.estado_lote = datos.estado_lote\n\n        if datos.cantidad_kg is not None:\n            lote.cantidad_kg = datos.cantidad_kg\n        if datos.observaciones is not None:\n            lote.observaciones = datos.observaciones\n\n        self.db.commit()\n        self.db.refresh(lote)\n        logger.info(\n            f"Lote actualizado: id={lote_id} estado=\'{lote.estado_lote}\'"\n        )\n        return lote\n\n    def eliminar_lote(\n        self, lote_id: int, usuario_id: int\n    ) -> None:\n        """RNF-05: eliminacion logica del lote."""\n        lote = self.obtener_lote(lote_id, usuario_id)\n        lote.estado_lote = "eliminado"\n        self.db.commit()\n        logger.info(f"Lote eliminado (logico): id={lote_id}")\n\n    # ----------------------------------------------------------\n    # SENSORES - RNF-06, RNF-09\n    # ----------------------------------------------------------\n\n    def registrar_sensor(\n        self, cultivo_id: int, datos: SensorCreate, usuario_id: int\n    ) -> Sensor:\n        """\n        RNF-06: registra un nuevo sensor IoT sin cambios de arquitectura.\n        El sensor queda vinculado al cultivo y empieza en estado \'activo\'.\n        """\n        self.obtener_cultivo(cultivo_id, usuario_id)\n\n        existente = self.db.query(Sensor).filter(\n            Sensor.codigo_sensor == datos.codigo_sensor\n        ).first()\n        if existente:\n            raise HTTPException(\n                status_code=status.HTTP_409_CONFLICT,\n                detail=f"Ya existe un sensor con codigo \'{datos.codigo_sensor}\'",\n            )\n\n        sensor = Sensor(\n            codigo_sensor=datos.codigo_sensor,\n            tipo_sensor=datos.tipo_sensor,\n            descripcion=datos.descripcion,\n            unidad_medida=datos.unidad_medida,\n            fecha_instalacion=datos.fecha_instalacion,\n            estado="activo",\n            id_cultivo=cultivo_id,\n        )\n        self.db.add(sensor)\n        self.db.commit()\n        self.db.refresh(sensor)\n        logger.info(\n            f"Sensor registrado: codigo=\'{sensor.codigo_sensor}\' "\n            f"tipo=\'{sensor.tipo_sensor}\' cultivo={cultivo_id}"\n        )\n        return sensor\n\n    def listar_sensores(\n        self, cultivo_id: int, usuario_id: int\n    ) -> List[Sensor]:\n        self.obtener_cultivo(cultivo_id, usuario_id)\n        return (\n            self.db.query(Sensor)\n            .filter(Sensor.id_cultivo == cultivo_id)\n            .order_by(Sensor.codigo_sensor)\n            .all()\n        )\n\n    # ----------------------------------------------------------\n    # METODOS PRIVADOS\n    # ----------------------------------------------------------\n\n    def _validar_transicion_cultivo(\n        self, estado_actual: str, estado_nuevo: str\n    ) -> None:\n        """\n        Valida que la transicion de estado del cultivo sea\n        coherente con el diagrama de estados oficial del proyecto.\n        """\n        permitidos = TRANSICIONES_CULTIVO.get(estado_actual, set())\n        if estado_nuevo not in permitidos:\n            raise HTTPException(\n                status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                detail=(\n                    f"Transicion invalida en el cultivo: "\n                    f"\'{estado_actual}\' no puede cambiar a \'{estado_nuevo}\'. "\n                    f"Transiciones permitidas: {sorted(permitidos)}"\n                ),\n            )\n\n    def _validar_transicion_lote(\n        self, estado_actual: str, estado_nuevo: str\n    ) -> None:\n        """\n        Valida que la transicion de estado del lote sea coherente\n        con el diagrama de estados oficial del proyecto.\n        """\n        permitidos = TRANSICIONES_LOTE.get(estado_actual, set())\n        if estado_nuevo not in permitidos:\n            raise HTTPException(\n                status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                detail=(\n                    f"Transicion invalida en el lote: "\n                    f"\'{estado_actual}\' no puede cambiar a \'{estado_nuevo}\'. "\n                    f"Transiciones permitidas: {sorted(permitidos)}"\n                ),\n            )\n\n    def _verificar_trazabilidad_rn02(self, lote_id: int) -> None:\n        """\n        RN-02: verifica que el lote tenga registrada la etapa\n        \'comercializacion\' en tbl_trazabilidad antes de pasar a \'vendido\'.\n        Lanza HTTP 422 si la condicion no se cumple.\n        """\n        resultado = self.db.execute(\n            text(\n                "SELECT COUNT(*) FROM tbl_trazabilidad "\n                "WHERE id_lote = :lote_id AND etapa = \'comercializacion\'"\n            ),\n            {"lote_id": lote_id},\n        ).scalar()\n\n        if not resultado:\n            logger.warning(\n                f"RN-02 bloqueado: lote={lote_id} intento pasar a \'vendido\' "\n                "sin trazabilidad completa"\n            )\n            raise HTTPException(\n                status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                detail=(\n                    "RN-02: Este lote no puede marcarse como \'vendido\' todavia. "\n                    "Primero debe registrar la etapa \'comercializacion\' "\n                    "en el modulo de Trazabilidad."\n                ),\n            )\n'

ARCHIVOS["frontend/src/pages/Monitoreo.jsx"] = '// ==============================================================\n// modulo_03_monitoreo / frontend/src/pages/Monitoreo.jsx\n// Dashboard de Monitoreo Ambiental y Suelo\n//\n// RF-03  Visualiza variables ambientales en tiempo real\n// RF-04  Visualiza estado del suelo con interpretacion\n// RN-03  Indicador de validez de datos para IA\n// RNF-02 Usabilidad para usuarios sin perfil tecnico\n// RNF-07 Responsive - funciona en web y movil\n// ==============================================================\n\nimport { useState } from "react";\nimport { useMonitoreo, useHistorialAmbiental, useHistorialSuelo } from "../hooks/useMonitoreo";\nimport FormularioAmbiental from "../components/FormularioAmbiental";\nimport FormularioSuelo     from "../components/FormularioSuelo";\n\n// ==============================================================\n// CONSTANTES DE DISENO\n// ==============================================================\nconst COLOR = {\n  cafe:     "#6f3a1b",\n  cafeCla:  "#a0522d",\n  verde:    "#2d7a3a",\n  amarillo: "#c8a000",\n  rojo:     "#b91c1c",\n  azul:     "#0284c7",\n  gris:     "#f5f0eb",\n  borde:    "#d4b896",\n  texto:    "#1a0e05",\n};\n\n// ==============================================================\n// SUBCOMPONENTES\n// ==============================================================\n\nfunction Modal({ abierto, titulo, onCerrar, children }) {\n  if (!abierto) return null;\n  return (\n    <div style={{\n      position: "fixed", inset: 0, background: "rgba(0,0,0,0.4)",\n      display: "flex", alignItems: "center", justifyContent: "center",\n      zIndex: 1000, padding: "1rem",\n    }}>\n      <div style={{\n        background: "#fff", borderRadius: "16px", padding: "2rem",\n        width: "100%", maxWidth: "540px", maxHeight: "90vh",\n        overflowY: "auto", boxShadow: "0 20px 60px rgba(0,0,0,0.3)",\n      }}>\n        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1.5rem" }}>\n          <h3 style={{ margin: 0, color: COLOR.cafe }}>{titulo}</h3>\n          <button onClick={onCerrar}\n            style={{ background: "none", border: "none", fontSize: "1.4rem", cursor: "pointer" }}>\n            x\n          </button>\n        </div>\n        {children}\n      </div>\n    </div>\n  );\n}\n\nfunction TarjetaMetrica({ icono, etiqueta, valor, unidad, estado = "normal" }) {\n  const colores = {\n    normal:   { bg: "#fff",     borde: COLOR.borde,   texto: COLOR.cafe  },\n    alerta:   { bg: "#fffbeb",  borde: COLOR.amarillo, texto: COLOR.amarillo },\n    critico:  { bg: "#fff1f0",  borde: COLOR.rojo,    texto: COLOR.rojo  },\n    optimo:   { bg: "#f0fdf4",  borde: COLOR.verde,   texto: COLOR.verde },\n  };\n  const c = colores[estado] || colores.normal;\n  return (\n    <div style={{\n      background: c.bg, border: `1.5px solid ${c.borde}`,\n      borderRadius: "12px", padding: "1rem 1.2rem",\n      display: "flex", alignItems: "center", gap: "0.8rem",\n    }}>\n      <span style={{ fontSize: "1.8rem" }}>{icono}</span>\n      <div>\n        <p style={{ margin: 0, fontSize: "0.78rem", color: "#7a5c3a", fontWeight: 600 }}>\n          {etiqueta}\n        </p>\n        <p style={{ margin: 0, fontSize: "1.5rem", fontWeight: 800, color: c.texto }}>\n          {valor !== null && valor !== undefined ? `${valor}` : "-"}\n          {valor !== null && valor !== undefined && unidad && (\n            <span style={{ fontSize: "0.85rem", fontWeight: 400 }}> {unidad}</span>\n          )}\n        </p>\n      </div>\n    </div>\n  );\n}\n\nfunction BannerValidez({ validez }) {\n  if (!validez) return null;\n  const esValido = validez.ambos_validos;\n  return (\n    <div style={{\n      background:   esValido ? "#f0fdf4" : "#fffbeb",\n      border:       `1.5px solid ${esValido ? COLOR.verde : COLOR.amarillo}`,\n      borderRadius: "12px",\n      padding:      "1rem 1.4rem",\n      display:      "flex",\n      alignItems:   "center",\n      gap:          "0.8rem",\n    }}>\n      <span style={{ fontSize: "1.5rem" }}>{esValido ? "✅" : "⚠️"}</span>\n      <div>\n        <p style={{ margin: 0, fontWeight: 700, color: esValido ? COLOR.verde : COLOR.amarillo }}>\n          {esValido\n            ? "Datos actualizados - IA habilitada"\n            : "Datos desactualizados - IA no disponible"}\n        </p>\n        <p style={{ margin: "0.2rem 0 0", fontSize: "0.83rem", color: "#7a5c3a" }}>\n          {validez.mensaje}\n        </p>\n      </div>\n      <div style={{ marginLeft: "auto", textAlign: "right", fontSize: "0.78rem", color: "#9a7a5a" }}>\n        <p style={{ margin: 0 }}>Amb: {\n          validez.horas_desde_ambiental\n            ? `hace ${validez.horas_desde_ambiental.toFixed(1)} h`\n            : "Sin datos"\n        }</p>\n        <p style={{ margin: 0 }}>Suelo: {\n          validez.horas_desde_suelo\n            ? `hace ${validez.horas_desde_suelo.toFixed(1)} h`\n            : "Sin datos"\n        }</p>\n      </div>\n    </div>\n  );\n}\n\nfunction FilaHistorial({ fecha, origen, variables }) {\n  const etiquetaOrigen = {\n    manual:      "Manual",\n    sensor_iot:  "Sensor IoT",\n    laboratorio: "Laboratorio",\n    api_externa: "API ext.",\n  };\n  return (\n    <div style={{\n      border: `1px solid ${COLOR.borde}`,\n      borderRadius: "8px",\n      padding: "0.75rem 1rem",\n      background: "#fafaf8",\n      display: "flex",\n      justifyContent: "space-between",\n      alignItems: "center",\n      gap: "1rem",\n    }}>\n      <div style={{ fontSize: "0.8rem", color: "#9a7a5a" }}>\n        <p style={{ margin: 0, fontWeight: 600 }}>\n          {new Date(fecha).toLocaleDateString("es-CO", {\n            day: "2-digit", month: "short", year: "numeric",\n            hour: "2-digit", minute: "2-digit",\n          })}\n        </p>\n        <span style={{\n          background: "#e8ddd4", color: COLOR.cafe,\n          borderRadius: "4px", padding: "1px 6px", fontSize: "0.73rem",\n        }}>\n          {etiquetaOrigen[origen] || origen}\n        </span>\n      </div>\n      <div style={{ display: "flex", gap: "1.5rem", flexWrap: "wrap" }}>\n        {variables.map(({ etiqueta, valor, unidad }) =>\n          valor !== null && valor !== undefined ? (\n            <div key={etiqueta} style={{ textAlign: "center" }}>\n              <p style={{ margin: 0, fontSize: "0.73rem", color: "#9a7a5a" }}>{etiqueta}</p>\n              <p style={{ margin: 0, fontSize: "0.92rem", fontWeight: 700, color: COLOR.cafe }}>\n                {valor} <span style={{ fontWeight: 400, fontSize: "0.78rem" }}>{unidad}</span>\n              </p>\n            </div>\n          ) : null\n        )}\n      </div>\n    </div>\n  );\n}\n\n// ==============================================================\n// DETERMINACION DE ESTADO DE ALERTA DE UNA METRICA\n// ==============================================================\nfunction estadoTemp(v) {\n  if (v === null || v === undefined) return "normal";\n  if (v < 14 || v > 30) return "critico";\n  if (v < 18 || v > 24) return "alerta";\n  return "optimo";\n}\nfunction estadoHumRel(v) {\n  if (v === null || v === undefined) return "normal";\n  if (v < 55 || v > 95) return "critico";\n  if (v < 70 || v > 90) return "alerta";\n  return "optimo";\n}\nfunction estadoPH(v) {\n  if (v === null || v === undefined) return "normal";\n  if (v < 4.5 || v > 7.5) return "critico";\n  if (v < 5.5 || v > 6.5) return "alerta";\n  return "optimo";\n}\n\n// ==============================================================\n// COMPONENTE PRINCIPAL\n// ==============================================================\n\nexport default function Monitoreo() {\n  // F-C01 + N-002 FIX: leer de sessionStorage (escrito por Cultivos.jsx al seleccionar)\n  const cultivoId     = parseInt(sessionStorage.getItem("gv_cultivo_id") || "1", 10);\n  const cultivoNombre = sessionStorage.getItem("gv_cultivo_nombre") || "Mi Cultivo";\n\n  const { resumen, validez, cargando, error, recargar } = useMonitoreo(cultivoId, 60);\n  const { historial: histAmb, recargar: recargarAmb }   = useHistorialAmbiental(cultivoId, 15);\n  const { historial: histSue, recargar: recargarSue }   = useHistorialSuelo(cultivoId, 15);\n\n  const [modalAmb,    setModalAmb]    = useState(false);\n  const [modalSuelo,  setModalSuelo]  = useState(false);\n  const [tabActiva,   setTabActiva]   = useState("ambiental");\n\n  const alGuardarAmb = () => {\n    setModalAmb(false);\n    recargar();\n    recargarAmb();\n  };\n  const alGuardarSuelo = () => {\n    setModalSuelo(false);\n    recargar();\n    recargarSue();\n  };\n\n  // ==============================================================\n  // RENDER\n  // ==============================================================\n\n  if (cargando && !resumen) {\n    return (\n      <div style={estilos.contenedor}>\n        <p style={{ textAlign: "center", color: COLOR.cafeCla, padding: "3rem" }}>\n          Cargando datos de monitoreo...\n        </p>\n      </div>\n    );\n  }\n\n  return (\n    <div style={estilos.contenedor}>\n\n      {/* Encabezado */}\n      <div style={estilos.encabezado}>\n        <div>\n          <h1 style={estilos.titulo}>🌡️ Monitoreo</h1>\n          <p style={{ margin: 0, color: "#7a5c3a" }}>{cultivoNombre}</p>\n        </div>\n        <div style={{ display: "flex", gap: "0.8rem" }}>\n          <button onClick={() => setModalAmb(true)} style={estilos.botonVerde}>\n            + Ambiental\n          </button>\n          <button onClick={() => setModalSuelo(true)} style={estilos.botonCafe}>\n            + Suelo\n          </button>\n        </div>\n      </div>\n\n      {/* Error global */}\n      {error && (\n        <div style={estilos.alerta} role="alert">{error}</div>\n      )}\n\n      {/* Banner de validez RN-03 */}\n      <BannerValidez validez={validez} />\n\n      {/* Alertas activas */}\n      {resumen?.alertas?.length > 0 && (\n        <div style={{\n          background: "#fffbeb", border: `1px solid ${COLOR.amarillo}`,\n          borderRadius: "12px", padding: "1rem 1.4rem",\n        }}>\n          <p style={{ margin: "0 0 0.5rem", fontWeight: 700, color: COLOR.amarillo }}>\n            Alertas activas ({resumen.alertas.length})\n          </p>\n          {resumen.alertas.map((a, i) => (\n            <p key={i} style={{ margin: "0.25rem 0", fontSize: "0.85rem", color: "#7a5c3a" }}>\n              - {a}\n            </p>\n          ))}\n        </div>\n      )}\n\n      {/* Metricas ambientales */}\n      <section>\n        <h2 style={estilos.seccion}>Variables Ambientales</h2>\n        <div style={estilos.gridMetricas}>\n          <TarjetaMetrica\n            icono="🌡️" etiqueta="Temperatura"\n            valor={resumen?.ultima_temperatura}\n            unidad="C"\n            estado={estadoTemp(resumen?.ultima_temperatura)}\n          />\n          <TarjetaMetrica\n            icono="💧" etiqueta="Humedad relativa"\n            valor={resumen?.ultima_humedad_rel}\n            unidad="%"\n            estado={estadoHumRel(resumen?.ultima_humedad_rel)}\n          />\n          <TarjetaMetrica\n            icono="🌧️" etiqueta="Precipitacion"\n            valor={resumen?.ultima_precipitacion}\n            unidad="mm"\n          />\n        </div>\n      </section>\n\n      {/* Metricas de suelo */}\n      <section>\n        <h2 style={estilos.seccion}>Estado del Suelo</h2>\n        <div style={estilos.gridMetricas}>\n          <TarjetaMetrica\n            icono="🧪" etiqueta="pH del suelo"\n            valor={resumen?.ultimo_ph}\n            estado={estadoPH(resumen?.ultimo_ph)}\n          />\n          <TarjetaMetrica\n            icono="💦" etiqueta="Humedad suelo"\n            valor={resumen?.ultima_humedad_suelo}\n            unidad="%"\n          />\n          <TarjetaMetrica\n            icono="🌿" etiqueta="Nitrogeno"\n            valor={resumen?.ultimo_nitrogeno}\n            unidad="mg/kg"\n            estado={\n              resumen?.ultimo_nitrogeno !== null && resumen?.ultimo_nitrogeno < 20\n                ? "alerta" : "normal"\n            }\n          />\n        </div>\n      </section>\n\n      {/* Historial con tabs */}\n      <section>\n        <div style={{ display: "flex", gap: 0, borderBottom: `2px solid ${COLOR.borde}`, marginBottom: "1rem" }}>\n          {["ambiental", "suelo"].map(tab => (\n            <button\n              key={tab}\n              onClick={() => setTabActiva(tab)}\n              style={{\n                padding:    "0.6rem 1.5rem",\n                border:     "none",\n                background: "none",\n                fontWeight: tabActiva === tab ? 800 : 400,\n                color:      tabActiva === tab ? COLOR.cafe : "#9a7a5a",\n                borderBottom: tabActiva === tab ? `3px solid ${COLOR.cafe}` : "3px solid transparent",\n                cursor:     "pointer",\n                fontSize:   "0.92rem",\n                marginBottom: "-2px",\n              }}\n            >\n              {tab === "ambiental" ? "Historial Ambiental" : "Historial Suelo"}\n            </button>\n          ))}\n        </div>\n\n        {tabActiva === "ambiental" && (\n          <div style={{ display: "flex", flexDirection: "column", gap: "0.6rem" }}>\n            {histAmb.length === 0 ? (\n              <p style={{ color: "#bbb", fontSize: "0.9rem" }}>\n                Sin lecturas ambientales registradas.\n              </p>\n            ) : (\n              histAmb.map(r => (\n                <FilaHistorial\n                  key={r.id_monitoreo}\n                  fecha={r.fecha_registro}\n                  origen={r.origen_dato}\n                  variables={[\n                    { etiqueta: "Temp",    valor: r.temperatura,       unidad: "C"    },\n                    { etiqueta: "Hum",     valor: r.humedad_relativa,  unidad: "%"    },\n                    { etiqueta: "Lluvia",  valor: r.precipitacion_mm,  unidad: "mm"   },\n                    { etiqueta: "Rad",     valor: r.radiacion_solar,   unidad: "W/m2" },\n                    { etiqueta: "Viento",  valor: r.velocidad_viento,  unidad: "km/h" },\n                  ]}\n                />\n              ))\n            )}\n          </div>\n        )}\n\n        {tabActiva === "suelo" && (\n          <div style={{ display: "flex", flexDirection: "column", gap: "0.6rem" }}>\n            {histSue.length === 0 ? (\n              <p style={{ color: "#bbb", fontSize: "0.9rem" }}>\n                Sin lecturas de suelo registradas.\n              </p>\n            ) : (\n              histSue.map(r => (\n                <FilaHistorial\n                  key={r.id_monitoreo_suelo}\n                  fecha={r.fecha_registro}\n                  origen={r.origen_dato}\n                  variables={[\n                    { etiqueta: "pH",   valor: r.ph,               unidad: ""       },\n                    { etiqueta: "Hum",  valor: r.humedad_suelo,    unidad: "%"      },\n                    { etiqueta: "N",    valor: r.nitrogeno,        unidad: "mg/kg"  },\n                    { etiqueta: "P",    valor: r.fosforo,          unidad: "mg/kg"  },\n                    { etiqueta: "K",    valor: r.potasio,          unidad: "mg/kg"  },\n                    { etiqueta: "M.O.", valor: r.materia_organica, unidad: "%"      },\n                  ]}\n                />\n              ))\n            )}\n          </div>\n        )}\n      </section>\n\n      {/* Modal - Ambiental */}\n      <Modal abierto={modalAmb} titulo="Registrar lectura ambiental" onCerrar={() => setModalAmb(false)}>\n        <FormularioAmbiental\n          cultivoId={cultivoId}\n          onGuardado={alGuardarAmb}\n          onCancelar={() => setModalAmb(false)}\n        />\n      </Modal>\n\n      {/* Modal - Suelo */}\n      <Modal abierto={modalSuelo} titulo="Registrar analisis de suelo" onCerrar={() => setModalSuelo(false)}>\n        <FormularioSuelo\n          cultivoId={cultivoId}\n          onGuardado={alGuardarSuelo}\n          onCancelar={() => setModalSuelo(false)}\n        />\n      </Modal>\n    </div>\n  );\n}\n\n// ==============================================================\n// ESTILOS\n// ==============================================================\n\nconst estilos = {\n  contenedor: {\n    minHeight:  "100vh",\n    background: COLOR.gris,\n    padding:    "2rem",\n    fontFamily: "\'Segoe UI\', Roboto, sans-serif",\n    color:      COLOR.texto,\n    display:    "flex",\n    flexDirection: "column",\n    gap:        "1.5rem",\n  },\n  encabezado: {\n    display:        "flex",\n    justifyContent: "space-between",\n    alignItems:     "center",\n  },\n  titulo: {\n    margin: 0, fontSize: "1.8rem",\n    fontWeight: 800, color: COLOR.cafe,\n  },\n  seccion: {\n    margin: "0 0 0.8rem",\n    fontSize: "1rem",\n    fontWeight: 700,\n    color: COLOR.cafe,\n    borderBottom: `2px solid ${COLOR.borde}`,\n    paddingBottom: "0.4rem",\n  },\n  gridMetricas: {\n    display:             "grid",\n    gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",\n    gap:                 "1rem",\n  },\n  alerta: {\n    background: "#fff1f0", border: "1px solid #ffccc7",\n    borderRadius: "8px", padding: "0.8rem 1rem",\n    color: COLOR.rojo, fontSize: "0.87rem",\n  },\n  botonVerde: {\n    padding: "0.6rem 1.2rem", borderRadius: "8px",\n    border: "none", background: "#dcfce7",\n    color: COLOR.verde, fontWeight: 700, cursor: "pointer",\n  },\n  botonCafe: {\n    padding: "0.6rem 1.2rem", borderRadius: "8px",\n    border: "none",\n    background: "linear-gradient(135deg, #6f3a1b, #a0522d)",\n    color: "#fff", fontWeight: 700, cursor: "pointer",\n  },\n};\n'

ARCHIVOS["frontend/src/pages/InteligenciaArtificial.jsx"] = '// ==============================================================\n// modulo_04_ia / frontend/src/pages/InteligenciaArtificial.jsx\n// Dashboard principal del Modulo de IA\n//\n// RF-05  Carga y analisis de imagen para enfermedades\n// RF-06  Carga y analisis de imagen para plagas\n// RF-07  Prediccion fitosanitaria con un clic\n// RF-08  Recomendacion de riego con un clic\n// RF-09  Recomendacion de fertilizacion con un clic\n// RN-03  Banner de validez de datos visible siempre\n// RNF-02 Interfaz para usuarios sin perfil tecnico\n// RNF-07 Responsive web y movil\n// ==============================================================\n\nimport { useState, useEffect, useRef } from "react";\nimport { iaService } from "../services/iaService";\n\n// ── Colores GranoVital ──────────────────────────────────────\nconst C = {\n  cafe:    "#6f3a1b", cafeCla: "#a0522d", verde:  "#2d7a3a",\n  amarillo:"#c8a000", rojo:    "#b91c1c", azul:   "#0284c7",\n  gris:    "#f5f0eb", borde:   "#d4b896", texto:  "#1a0e05",\n};\n\n// ── Paleta de urgencia ──────────────────────────────────────\nconst URGENCIA_COLOR = {\n  bajo:     { bg: "#f0fdf4", borde: C.verde,    texto: C.verde    },\n  medio:    { bg: "#fffbeb", borde: C.amarillo, texto: C.amarillo },\n  alto:     { bg: "#fff7ed", borde: "#ea580c",  texto: "#ea580c"  },\n  critico:  { bg: "#fff1f0", borde: C.rojo,     texto: C.rojo     },\n  moderado: { bg: "#fffbeb", borde: C.amarillo, texto: C.amarillo },\n};\nconst RIESGO_ICONO = { bajo:"🟢", moderado:"🟡", alto:"🟠", critico:"🔴" };\n\n// ── Subcomponentes ───────────────────────────────────────────\n\nfunction Modal({ abierto, titulo, onCerrar, children }) {\n  if (!abierto) return null;\n  return (\n    <div style={{\n      position:"fixed", inset:0, background:"rgba(0,0,0,0.45)",\n      display:"flex", alignItems:"center", justifyContent:"center",\n      zIndex:1000, padding:"1rem",\n    }}>\n      <div style={{\n        background:"#fff", borderRadius:"16px", padding:"2rem",\n        width:"100%", maxWidth:"580px", maxHeight:"90vh",\n        overflowY:"auto", boxShadow:"0 20px 60px rgba(0,0,0,0.3)",\n      }}>\n        <div style={{ display:"flex", justifyContent:"space-between", marginBottom:"1.5rem" }}>\n          <h3 style={{ margin:0, color:C.cafe }}>{titulo}</h3>\n          <button onClick={onCerrar}\n            style={{ background:"none", border:"none", fontSize:"1.4rem", cursor:"pointer" }}>✕</button>\n        </div>\n        {children}\n      </div>\n    </div>\n  );\n}\n\nfunction Badge({ texto, urgencia = "bajo" }) {\n  const col = URGENCIA_COLOR[urgencia] || URGENCIA_COLOR.bajo;\n  return (\n    <span style={{\n      background:col.bg, border:`1.5px solid ${col.borde}`,\n      color:col.texto, borderRadius:"999px",\n      padding:"0.2rem 0.8rem", fontSize:"0.78rem", fontWeight:700,\n    }}>\n      {texto}\n    </span>\n  );\n}\n\nfunction BannerRN03({ validez }) {\n  if (!validez) return null;\n  const ok = validez.datos_validos_rn03;\n  return (\n    <div style={{\n      background: ok ? "#f0fdf4" : "#fffbeb",\n      border:`1.5px solid ${ok ? C.verde : C.amarillo}`,\n      borderRadius:"12px", padding:"1rem 1.4rem",\n      display:"flex", alignItems:"center", gap:"0.8rem",\n    }}>\n      <span style={{ fontSize:"1.5rem" }}>{ok ? "✅" : "⚠️"}</span>\n      <div>\n        <p style={{ margin:0, fontWeight:700, color: ok ? C.verde : C.amarillo }}>\n          {ok ? "Datos actualizados — IA completamente disponible"\n               : "Datos desactualizados — IA limitada (RN-03)"}\n        </p>\n        <p style={{ margin:"0.2rem 0 0", fontSize:"0.83rem", color:"#7a5c3a" }}>\n          {/* F-M05 FIX: mensaje amigable con instrucción accionable */}\n          {validez.datos_validos_rn03\n            ? validez.mensaje_rn03\n            : "Tus datos de monitoreo están desactualizados. Registra una nueva lectura en Monitoreo para activar la IA."}\n        </p>\n      </div>\n    </div>\n  );\n}\n\nfunction TarjetaResultado({ titulo, icono, datos, cargando, error, onAccion, textoAccion, urgencia }) {\n  const col = URGENCIA_COLOR[urgencia] || { bg:"#fff", borde:C.borde };\n  return (\n    <div style={{\n      background:col.bg, border:`1.5px solid ${col.borde}`,\n      borderRadius:"14px", padding:"1.2rem 1.4rem",\n    }}>\n      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"0.8rem" }}>\n        <h3 style={{ margin:0, fontSize:"1rem", color:C.cafe }}>\n          {icono} {titulo}\n        </h3>\n        {onAccion && (\n          <button onClick={onAccion} disabled={cargando}\n            style={{\n              padding:"0.45rem 1rem", borderRadius:"8px", border:"none",\n              background: cargando ? "#c9a88a" : C.cafe,\n              color:"#fff", fontWeight:700, cursor: cargando ? "not-allowed" : "pointer",\n              fontSize:"0.82rem",\n            }}>\n            {cargando ? "Analizando..." : textoAccion || "Ejecutar"}\n          </button>\n        )}\n      </div>\n\n      {error && (\n        <div style={{\n          background:"#fff1f0", border:"1px solid #ffccc7",\n          borderRadius:"8px", padding:"0.6rem", color:C.rojo,\n          fontSize:"0.83rem", marginBottom:"0.6rem",\n        }}>\n          {error}\n        </div>\n      )}\n\n      {datos && (\n        <div style={{ fontSize:"0.88rem", lineHeight:1.6 }}>\n          {datos}\n        </div>\n      )}\n\n      {!datos && !cargando && !error && (\n        <p style={{ color:"#bbb", fontSize:"0.85rem", margin:0 }}>\n          Sin resultados aun. Ejecute el analisis.\n        </p>\n      )}\n    </div>\n  );\n}\n\n// ── Panel de imagen para RF-05 / RF-06 ───────────────────────\n\nfunction PanelImagen({ tipo, cultivoId, onResultado }) {\n  const [archivo,   setArchivo]   = useState(null);\n  const [preview,   setPreview]   = useState(null);\n  const [cargando,  setCargando]  = useState(false);\n  const [error,     setError]     = useState("");\n  const [resultado, setResultado] = useState(null);\n  const inputRef = useRef();\n\n  const seleccionar = (e) => {\n    const f = e.target.files[0];\n    if (!f) return;\n    setArchivo(f);\n    setPreview(URL.createObjectURL(f));\n    setResultado(null);\n    setError("");\n  };\n\n  const analizar = async () => {\n    if (!archivo) return;\n    setCargando(true);\n    setError("");\n    try {\n      const fn   = tipo === "enfermedad"\n        ? iaService.analizarEnfermedad\n        : iaService.analizarPlaga;\n      const res  = await fn(cultivoId, archivo);\n      setResultado(res);\n      onResultado && onResultado(res);\n    } catch (e) {\n      setError(e.message);\n    } finally {\n      setCargando(false);\n    }\n  };\n\n  const col = resultado ? (URGENCIA_COLOR[resultado.nivel_urgencia] || URGENCIA_COLOR.bajo) : null;\n\n  return (\n    <div style={{ display:"flex", flexDirection:"column", gap:"1rem" }}>\n      {/* Zona de carga */}\n      <div\n        onClick={() => inputRef.current.click()}\n        style={{\n          border:`2px dashed ${C.borde}`, borderRadius:"12px",\n          padding:"2rem", textAlign:"center", cursor:"pointer",\n          background: preview ? "#000" : C.gris,\n          position:"relative", overflow:"hidden", minHeight:"180px",\n          display:"flex", alignItems:"center", justifyContent:"center",\n        }}\n      >\n        {preview\n          ? <img src={preview} alt="preview"\n              style={{ maxWidth:"100%", maxHeight:"250px", borderRadius:"8px" }} />\n          : <div>\n              <p style={{ fontSize:"2.5rem", margin:"0 0 0.5rem" }}>📷</p>\n              <p style={{ margin:0, color:C.cafeCla, fontWeight:600 }}>\n                Haga clic para seleccionar imagen\n              </p>\n              <p style={{ margin:0, fontSize:"0.78rem", color:"#9a7a5a" }}>\n                JPG, PNG o WEBP — max 10 MB\n              </p>\n            </div>\n        }\n        <input ref={inputRef} type="file" accept="image/*"\n          onChange={seleccionar} style={{ display:"none" }} />\n      </div>\n\n      {archivo && (\n        <button onClick={analizar} disabled={cargando}\n          style={{\n            padding:"0.75rem", borderRadius:"10px", border:"none",\n            background: cargando ? "#c9a88a"\n              : "linear-gradient(135deg, #6f3a1b, #a0522d)",\n            color:"#fff", fontWeight:800, fontSize:"1rem",\n            cursor: cargando ? "not-allowed" : "pointer",\n          }}>\n          {cargando ? "⏳ Analizando imagen..." : "🔬 Analizar imagen"}\n        </button>\n      )}\n\n      {error && (\n        <div style={{\n          background:"#fff1f0", border:"1px solid #ffccc7",\n          borderRadius:"8px", padding:"0.8rem", color:C.rojo,\n        }}>{error}</div>\n      )}\n\n      {resultado && resultado.modo_simulado && (\n        <div style={{\n          background:"#c0392b", color:"#fff",\n          padding:"8px 12px", borderRadius:"8px",\n          fontWeight:700, fontSize:"0.85rem",\n          marginBottom:"4px",\n        }}>\n          ⚠️ MODO DEMOSTRACIÓN: este diagnóstico es simulado y NO refleja la imagen real.\n        </div>\n      )}\n\n      {resultado && col && (\n        <div style={{\n          background:col.bg, border:`2px solid ${col.borde}`,\n          borderRadius:"12px", padding:"1.2rem",\n        }}>\n          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>\n            <h4 style={{ margin:0, color:col.texto }}>{resultado.diagnostico}</h4>\n            <Badge texto={resultado.nivel_urgencia.toUpperCase()} urgencia={resultado.nivel_urgencia} />\n          </div>\n          <p style={{ margin:"0.4rem 0", fontSize:"0.85rem", color:"#7a5c3a" }}>\n            Confianza: <strong>{resultado.confianza_pct}</strong>\n            {" · "}{resultado.tiempo_pct_rnf01}\n          </p>\n\n          {/* Top clases */}\n          <div style={{ margin:"0.8rem 0", display:"flex", gap:"0.5rem", flexWrap:"wrap" }}>\n            {resultado.top_clases.map(c => (\n              <span key={c.clase} style={{\n                background:"rgba(0,0,0,0.06)", borderRadius:"6px",\n                padding:"0.2rem 0.6rem", fontSize:"0.78rem",\n              }}>\n                {c.clase} {(c.probabilidad * 100).toFixed(0)}%\n              </span>\n            ))}\n          </div>\n\n          <hr style={{ border:"none", borderTop:`1px solid ${col.borde}`, margin:"0.8rem 0" }} />\n          <p style={{ margin:0, fontSize:"0.85rem", lineHeight:1.7 }}>\n            <strong>Recomendacion:</strong><br />{resultado.recomendacion}\n          </p>\n        </div>\n      )}\n    </div>\n  );\n}\n\n// ── Componente principal ─────────────────────────────────────\n\nexport default function InteligenciaArtificial() {\n  // F-C01 FIX: leer cultivoId de sessionStorage (escrito por Cultivos.jsx al seleccionar)\n  const cultivoId     = parseInt(sessionStorage.getItem("gv_cultivo_id") || "1", 10);\n  const cultivoNombre = sessionStorage.getItem("gv_cultivo_nombre") || "Mi Cultivo";\n  const [resumen,  setResumen]  = useState(null);\n  const [cargando, setCargando] = useState(true);\n\n  // Estados de cada modelo\n  const [fito,    setFito]    = useState(null);\n  const [riego,   setRiego]   = useState(null);\n  const [fert,    setFert]    = useState(null);\n  const [loadF,   setLoadF]   = useState(false);\n  const [loadR,   setLoadR]   = useState(false);\n  const [loadFe,  setLoadFe]  = useState(false);\n  const [errF,    setErrF]    = useState("");\n  const [errR,    setErrR]    = useState("");\n  const [errFe,   setErrFe]   = useState("");\n\n  const [tabActiva, setTabActiva] = useState("enfermedades");\n\n  useEffect(() => {\n    iaService.resumen(cultivoId)\n      .then(setResumen)\n      .catch(() => {})\n      .finally(() => setCargando(false));\n  }, []);\n\n  const ejecutarFito = async () => {\n    setLoadF(true); setErrF("");\n    try { setFito(await iaService.predecirFitosanitario(cultivoId)); }\n    catch(e) { setErrF(e.message); }\n    finally { setLoadF(false); }\n  };\n\n  const ejecutarRiego = async () => {\n    setLoadR(true); setErrR("");\n    try { setRiego(await iaService.recomendarRiego(cultivoId)); }\n    catch(e) { setErrR(e.message); }\n    finally { setLoadR(false); }\n  };\n\n  const ejecutarFert = async () => {\n    setLoadFe(true); setErrFe("");\n    try { setFert(await iaService.recomendarFertilizacion(cultivoId)); }\n    catch(e) { setErrFe(e.message); }\n    finally { setLoadFe(false); }\n  };\n\n  // ── Renderizado de cada resultado ──────────────────────────\n\n  const datosFito = fito && (\n    <div>\n      <p style={{ margin:"0 0 0.4rem" }}>\n        {RIESGO_ICONO[fito.nivel_riesgo]} Nivel de riesgo:{" "}\n        <strong>{fito.nivel_riesgo.toUpperCase()}</strong> — {fito.probabilidad_pct}\n      </p>\n      {fito.factores_riesgo.map((f, i) => (\n        <p key={i} style={{ margin:"0.15rem 0", fontSize:"0.82rem", color:"#7a5c3a" }}>\n          · {f}\n        </p>\n      ))}\n      <hr style={{ border:"none", borderTop:`1px solid ${C.borde}`, margin:"0.8rem 0" }} />\n      <p style={{ margin:0 }}><strong>Recomendacion:</strong><br />{fito.recomendacion}</p>\n    </div>\n  );\n\n  const datosRiego = riego && (\n    <div>\n      <p style={{ margin:"0 0 0.4rem" }}>\n        Necesita riego:{" "}\n        <strong style={{ color: riego.necesita_riego === "si" ? C.rojo : C.verde }}>\n          {riego.necesita_riego.toUpperCase()}\n        </strong>\n        {riego.cantidad_litros_m2 && ` — ${riego.cantidad_litros_m2} L/m²`}\n        {riego.frecuencia_dias    && ` — cada ${riego.frecuencia_dias} dia(s)`}\n      </p>\n      <p style={{ margin:"0.3rem 0", fontSize:"0.82rem", color:"#7a5c3a" }}>\n        {riego.justificacion}\n      </p>\n      <hr style={{ border:"none", borderTop:`1px solid ${C.borde}`, margin:"0.8rem 0" }} />\n      <p style={{ margin:0 }}><strong>Accion:</strong><br />{riego.recomendacion}</p>\n    </div>\n  );\n\n  const datosFert = fert && (\n    <div>\n      <p style={{ margin:"0 0 0.4rem" }}>\n        Fertilizante: <strong>{fert.tipo_fertilizante}</strong>\n      </p>\n      {fert.dosis_kg_ha && (\n        <p style={{ margin:"0 0 0.25rem", fontSize:"0.83rem" }}>\n          Dosis: {fert.dosis_kg_ha} kg/ha · {fert.frecuencia_aplicacion}\n        </p>\n      )}\n      {fert.nutrientes_deficientes.length > 0 && (\n        <p style={{ margin:"0 0 0.5rem", fontSize:"0.82rem", color:"#7a5c3a" }}>\n          Deficiencias: {fert.nutrientes_deficientes.join(", ")}\n        </p>\n      )}\n      <hr style={{ border:"none", borderTop:`1px solid ${C.borde}`, margin:"0.8rem 0" }} />\n      <p style={{ margin:0 }}><strong>Plan:</strong><br />{fert.recomendacion}</p>\n    </div>\n  );\n\n  if (!cultivoId || cultivoId === 1 && !sessionStorage.getItem("gv_cultivo_id")) return (\n    <div style={{ padding:"2rem", textAlign:"center", color:"#6f3a1b" }}>\n      <p style={{ fontSize:"1.1rem", fontWeight:600 }}>⚠️ No hay cultivo seleccionado</p>\n      <p style={{ color:"#9a7a5a" }}>Ve al módulo <strong>Cultivos</strong> y selecciona un cultivo para continuar.</p>\n    </div>\n  );\n  if (cargando) return (\n    <div style={estilos.contenedor}>\n      <p style={{ textAlign:"center", color:C.cafeCla, padding:"3rem" }}>\n        Cargando módulo de IA...\n      </p>\n    </div>\n  );\n\n  // ── Render principal ───────────────────────────────────────\n  const TABS = [\n    { id:"enfermedades",   label:"🍃 Enfermedades" },\n    { id:"plagas",         label:"🐛 Plagas"        },\n    { id:"prediccion",     label:"🌦️ Riesgo"        },\n    { id:"riego",          label:"💧 Riego"         },\n    { id:"fertilizacion",  label:"🌿 Fertilización" },\n  ];\n\n  return (\n    <div style={estilos.contenedor}>\n      {/* Encabezado */}\n      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>\n        <div>\n          <h1 style={{ margin:0, fontSize:"1.8rem", fontWeight:800, color:C.cafe }}>\n            🤖 Inteligencia Artificial\n          </h1>\n          <p style={{ margin:0, color:"#7a5c3a" }}>🌱 {cultivoNombre || `Cultivo #${cultivoId}`}</p>\n        </div>\n      </div>\n\n      {/* Banner RN-03 */}\n      <BannerRN03 validez={resumen} />\n\n      {/* Alertas del resumen */}\n      {resumen?.alertas?.length > 0 && (\n        <div style={{\n          background:"#fff7ed", border:`1px solid #ea580c`,\n          borderRadius:"12px", padding:"1rem 1.4rem",\n        }}>\n          <p style={{ margin:"0 0 0.5rem", fontWeight:700, color:"#ea580c" }}>\n            Alertas activas ({resumen.alertas.length})\n          </p>\n          {resumen.alertas.map((a, i) => (\n            <p key={i} style={{ margin:"0.2rem 0", fontSize:"0.85rem", color:"#7a5c3a" }}>\n              ⚠ {a}\n            </p>\n          ))}\n        </div>\n      )}\n\n      {/* Tabs */}\n      <div style={{\n        display:"flex", gap:0,\n        borderBottom:`2px solid ${C.borde}`,\n        overflowX:"auto",\n      }}>\n        {TABS.map(t => (\n          <button key={t.id} onClick={() => setTabActiva(t.id)}\n            style={{\n              padding:"0.6rem 1.2rem", border:"none", background:"none",\n              fontWeight: tabActiva === t.id ? 800 : 400,\n              color:      tabActiva === t.id ? C.cafe : "#9a7a5a",\n              borderBottom: tabActiva === t.id\n                ? `3px solid ${C.cafe}` : "3px solid transparent",\n              cursor:"pointer", fontSize:"0.88rem",\n              marginBottom:"-2px", whiteSpace:"nowrap",\n            }}>\n            {t.label}\n          </button>\n        ))}\n      </div>\n\n      {/* Contenido de cada tab */}\n      <div style={{ minHeight:"300px" }}>\n        {tabActiva === "enfermedades" && (\n          <div>\n            <p style={{ color:"#7a5c3a", fontSize:"0.88rem", marginBottom:"1rem" }}>\n              RF-05: suba una foto de una hoja de cafe para detectar Roya,\n              Mancha de Hierro, Antracnosis o CBD.\n            </p>\n            <PanelImagen tipo="enfermedad" cultivoId={cultivoId} />\n          </div>\n        )}\n\n        {tabActiva === "plagas" && (\n          <div>\n            <p style={{ color:"#7a5c3a", fontSize:"0.88rem", marginBottom:"1rem" }}>\n              RF-06: suba una foto del cultivo o fruto para identificar Broca,\n              Minador de la Hoja, Trips o Acaro Rojo.\n            </p>\n            <PanelImagen tipo="plaga" cultivoId={cultivoId} />\n          </div>\n        )}\n\n        {tabActiva === "prediccion" && (\n          <TarjetaResultado\n            titulo="Prediccion de Riesgo Fitosanitario"\n            icono="🌦️"\n            datos={datosFito}\n            cargando={loadF}\n            error={errF}\n            urgencia={fito?.nivel_riesgo}\n            onAccion={ejecutarFito}\n            textoAccion="Predecir riesgo ahora"\n          />\n        )}\n\n        {tabActiva === "riego" && (\n          <TarjetaResultado\n            titulo="Recomendacion de Riego"\n            icono="💧"\n            datos={datosRiego}\n            cargando={loadR}\n            error={errR}\n            urgencia={riego?.nivel_urgencia}\n            onAccion={ejecutarRiego}\n            textoAccion="Evaluar necesidad de riego"\n          />\n        )}\n\n        {tabActiva === "fertilizacion" && (\n          <TarjetaResultado\n            titulo="Plan de Fertilizacion"\n            icono="🌿"\n            datos={datosFert}\n            cargando={loadFe}\n            error={errFe}\n            urgencia={fert?.nivel_urgencia}\n            onAccion={ejecutarFert}\n            textoAccion="Generar plan de fertilizacion"\n          />\n        )}\n      </div>\n    </div>\n  );\n}\n\nconst estilos = {\n  contenedor: {\n    minHeight:"100vh", background:C.gris, padding:"2rem",\n    fontFamily:"\'Segoe UI\', Roboto, sans-serif", color:C.texto,\n    display:"flex", flexDirection:"column", gap:"1.5rem",\n  },\n};\n'

ARCHIVOS["frontend/src/pages/Cultivos.jsx"] = '// ==============================================================\n// modulo_02_cultivos / frontend/src/pages/Cultivos.jsx\n// Vista principal de Gestion de Cultivos y Lotes\n// RF-03 Cultivos | RF-04 Lotes | RNF-02 Usabilidad\n// RNF-07 Funciona en web y movil (responsive)\n// ==============================================================\n\nimport { useState, useEffect, useCallback } from "react";\nimport { cultivoService, loteService } from "../services/cultivoService";\n\n// Paleta de colores GranoVital\nconst COLOR = {\n  cafe:      "#6f3a1b",\n  cafeCLaro: "#a0522d",\n  verde:     "#2d7a3a",\n  amarillo:  "#c8a000",\n  rojo:      "#b91c1c",\n  gris:      "#f5f0eb",\n  texto:     "#1a0e05",\n  borde:     "#d4b896",\n};\n\n// Etiquetas de estado del Cultivo (diagrama de estados)\nconst ESTADO_CULTIVO = {\n  creado:                  { texto: "Creado",             color: COLOR.amarillo },\n  en_seguimiento:          { texto: "En Seguimiento",     color: COLOR.verde    },\n  con_problema_detectado:  { texto: "Con Problema",       color: COLOR.rojo     },\n  tratamiento_aplicado:    { texto: "En Tratamiento",     color: "#7c3aed"      },\n  finalizado:              { texto: "Finalizado",         color: "#64748b"      },\n  eliminado:               { texto: "Eliminado",          color: "#94a3b8"      },\n};\n\n// Etiquetas de estado del Lote (diagrama de estados)\nconst ESTADO_LOTE = {\n  registrado:  { texto: "Registrado",  color: COLOR.amarillo },\n  disponible:  { texto: "Disponible",  color: "#0284c7"      },\n  en_analisis: { texto: "En Analisis", color: "#7c3aed"      },\n  aprobado:    { texto: "Aprobado",    color: COLOR.verde    },\n  con_problema:{ texto: "Con Problema",color: COLOR.rojo     },\n  vendido:     { texto: "Vendido",     color: "#64748b"      },\n  eliminado:   { texto: "Eliminado",   color: "#94a3b8"      },\n};\n\n// ==============================================================\n// COMPONENTES REUTILIZABLES\n// ==============================================================\n\nfunction Badge({ estado, mapa }) {\n  const cfg = mapa[estado] || { texto: estado, color: "#94a3b8" };\n  return (\n    <span style={{\n      background:   cfg.color + "22",\n      color:        cfg.color,\n      border:       `1px solid ${cfg.color}55`,\n      borderRadius: "20px",\n      padding:      "3px 10px",\n      fontSize:     "0.78rem",\n      fontWeight:   700,\n    }}>\n      {cfg.texto}\n    </span>\n  );\n}\n\nfunction Tarjeta({ titulo, valor, icono, color }) {\n  return (\n    <div style={{\n      background:   "#fff",\n      border:       `1px solid ${COLOR.borde}`,\n      borderRadius: "12px",\n      padding:      "1.2rem 1.5rem",\n      display:      "flex",\n      alignItems:   "center",\n      gap:          "1rem",\n    }}>\n      <span style={{ fontSize: "2rem" }}>{icono}</span>\n      <div>\n        <p style={{ margin: 0, color: "#7a5c3a", fontSize: "0.8rem", fontWeight: 600 }}>\n          {titulo}\n        </p>\n        <p style={{ margin: 0, fontSize: "1.8rem", fontWeight: 800, color: color || COLOR.cafe }}>\n          {valor}\n        </p>\n      </div>\n    </div>\n  );\n}\n\nfunction Modal({ abierto, titulo, onCerrar, children }) {\n  if (!abierto) return null;\n  return (\n    <div style={{\n      position:   "fixed", inset: 0,\n      background: "rgba(0,0,0,0.4)",\n      display:    "flex",\n      alignItems: "center",\n      justifyContent: "center",\n      zIndex:     1000,\n      padding:    "1rem",\n    }}>\n      <div style={{\n        background:   "#fff",\n        borderRadius: "16px",\n        padding:      "2rem",\n        width:        "100%",\n        maxWidth:     "520px",\n        maxHeight:    "90vh",\n        overflowY:    "auto",\n        boxShadow:    "0 20px 60px rgba(0,0,0,0.3)",\n      }}>\n        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1.5rem" }}>\n          <h3 style={{ margin: 0, color: COLOR.cafe }}>{titulo}</h3>\n          <button\n            onClick={onCerrar}\n            style={{ background: "none", border: "none", fontSize: "1.5rem", cursor: "pointer" }}\n            aria-label="Cerrar modal"\n          >\n            x\n          </button>\n        </div>\n        {children}\n      </div>\n    </div>\n  );\n}\n\nfunction Campo({ label, name, value, onChange, type = "text", required = false, placeholder = "" }) {\n  return (\n    <div style={{ display: "flex", flexDirection: "column", gap: "0.3rem" }}>\n      <label style={{ fontSize: "0.83rem", fontWeight: 600, color: "#4a2c0a" }}>\n        {label}{required && " *"}\n      </label>\n      <input\n        name={name}\n        type={type}\n        value={value}\n        onChange={onChange}\n        required={required}\n        placeholder={placeholder}\n        style={{\n          padding: "0.6rem 0.9rem",\n          border: `1.5px solid ${COLOR.borde}`,\n          borderRadius: "8px",\n          fontSize: "0.9rem",\n          outline: "none",\n        }}\n      />\n    </div>\n  );\n}\n\nfunction Boton({ onClick, children, variante = "primario", tipo = "button", desactivado = false }) {\n  const estilosBase = {\n    padding:      "0.6rem 1.2rem",\n    borderRadius: "8px",\n    border:       "none",\n    fontSize:     "0.9rem",\n    fontWeight:   700,\n    cursor:       desactivado ? "not-allowed" : "pointer",\n    opacity:      desactivado ? 0.6 : 1,\n    transition:   "opacity 0.2s",\n  };\n\n  const variantes = {\n    primario:  { background: COLOR.cafe,      color: "#fff"     },\n    secundario:{ background: "#f5f0eb",        color: COLOR.cafe, border: `1px solid ${COLOR.borde}` },\n    peligro:   { background: "#fee2e2",        color: COLOR.rojo  },\n    verde:     { background: "#dcfce7",        color: COLOR.verde },\n  };\n\n  return (\n    <button\n      type={tipo}\n      onClick={onClick}\n      disabled={desactivado}\n      style={{ ...estilosBase, ...variantes[variante] }}\n    >\n      {children}\n    </button>\n  );\n}\n\n// ==============================================================\n// FORMULARIO CULTIVO\n// ==============================================================\n\nfunction FormularioCultivo({ onGuardar, onCancelar, inicial = {} }) {\n  const [form, setForm] = useState({\n    nombre_cultivo: inicial.nombre_cultivo || "",\n    ubicacion:      inicial.ubicacion      || "",\n    area_hectareas: inicial.area_hectareas || "",\n    variedad_cafe:  inicial.variedad_cafe  || "",\n    observaciones:  inicial.observaciones  || "",\n  });\n\n  const cambio = (e) => setForm(p => ({ ...p, [e.target.name]: e.target.value }));\n\n  const enviar = (e) => {\n    e.preventDefault();\n    onGuardar({\n      ...form,\n      area_hectareas: form.area_hectareas ? parseFloat(form.area_hectareas) : undefined,\n    });\n  };\n\n  return (\n    <form onSubmit={enviar} style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>\n      <Campo label="Nombre del cultivo" name="nombre_cultivo" value={form.nombre_cultivo}\n        onChange={cambio} required placeholder="Ej: Finca La Esperanza" />\n      <Campo label="Ubicacion" name="ubicacion" value={form.ubicacion}\n        onChange={cambio} placeholder="Ej: Andes, Antioquia - Coordenadas GPS" />\n      <Campo label="Area (hectareas)" name="area_hectareas" value={form.area_hectareas}\n        onChange={cambio} type="number" placeholder="Ej: 3.5" />\n      <Campo label="Variedad de cafe" name="variedad_cafe" value={form.variedad_cafe}\n        onChange={cambio} placeholder="Ej: Castillo, Caturra, Colombia" />\n      <Campo label="Observaciones" name="observaciones" value={form.observaciones}\n        onChange={cambio} placeholder="Informacion adicional del cultivo" />\n      <div style={{ display: "flex", gap: "0.8rem", justifyContent: "flex-end", marginTop: "0.5rem" }}>\n        <Boton variante="secundario" onClick={onCancelar}>Cancelar</Boton>\n        <Boton tipo="submit" variante="primario">Guardar</Boton>\n      </div>\n    </form>\n  );\n}\n\n// ==============================================================\n// FORMULARIO LOTE\n// ==============================================================\n\nfunction FormularioLote({ onGuardar, onCancelar }) {\n  const [form, setForm] = useState({\n    codigo_lote:   "",\n    cantidad_kg:   "",\n    fecha_cosecha: "",  // F-C03 FIX\n    observaciones: "",\n  });\n\n  const cambio = (e) => setForm(p => ({ ...p, [e.target.name]: e.target.value }));\n\n  const enviar = (e) => {\n    e.preventDefault();\n    onGuardar({\n      ...form,\n      codigo_lote:   form.codigo_lote.toUpperCase(),\n      cantidad_kg:   form.cantidad_kg ? parseFloat(form.cantidad_kg) : undefined,\n      // F-C03 FIX: enviar fecha como ISO con T12:00:00 para evitar desfase UTC (BUG-033)\n      fecha_cosecha: form.fecha_cosecha\n        ? new Date(form.fecha_cosecha + "T12:00:00").toISOString()\n        : undefined,\n    });\n  };\n\n  return (\n    <form onSubmit={enviar} style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>\n      <Campo label="Codigo del lote" name="codigo_lote" value={form.codigo_lote}\n        onChange={cambio} required placeholder="Ej: LOT-2025-001" />\n      <Campo label="Cantidad cosechada (kg)" name="cantidad_kg" value={form.cantidad_kg}\n        onChange={cambio} type="number" placeholder="Ej: 450" />\n      <Campo label="Fecha de cosecha" name="fecha_cosecha" value={form.fecha_cosecha}\n        onChange={cambio} type="date" required />\n      <Campo label="Observaciones" name="observaciones" value={form.observaciones}\n        onChange={cambio} placeholder="Notas sobre la cosecha" />\n      <div style={{ display: "flex", gap: "0.8rem", justifyContent: "flex-end", marginTop: "0.5rem" }}>\n        <Boton variante="secundario" onClick={onCancelar}>Cancelar</Boton>\n        <Boton tipo="submit" variante="primario">Registrar Lote</Boton>\n      </div>\n    </form>\n  );\n}\n\n// ==============================================================\n// VISTA PRINCIPAL\n// ==============================================================\n\nexport default function Cultivos() {\n  const [resumen,        setResumen]        = useState(null);\n  const [cultivos,       setCultivos]       = useState([]);\n  const [lotes,          setLotes]          = useState([]);\n  const [cultivoActivo,  setCultivoActivo]  = useState(null);\n  const [cargando,       setCargando]       = useState(true);\n  const [error,          setError]          = useState("");\n  const [modalCultivo,   setModalCultivo]   = useState(false);\n  const [modalLote,      setModalLote]      = useState(false);\n  const [editando,       setEditando]       = useState(null);\n  const nombreUsuario    = localStorage.getItem("nombre") || "Caficultor";\n\n  // Carga inicial\n  const cargarDatos = useCallback(async () => {\n    setCargando(true);\n    setError("");\n    try {\n      const [res, cvs] = await Promise.all([\n        cultivoService.resumen(),\n        cultivoService.listar(),\n      ]);\n      setResumen(res);\n      setCultivos(cvs);\n      if (cvs.length > 0 && !cultivoActivo) {\n        setCultivoActivo(cvs[0]);\n        sessionStorage.setItem("gv_cultivo_id",     String(cvs[0].id_cultivo));\n        sessionStorage.setItem("gv_cultivo_nombre", cvs[0].nombre_cultivo);\n        const ls = await loteService.listar(cvs[0].id_cultivo);\n        setLotes(ls);\n      }\n    } catch (e) {\n      setError(e.message);\n    } finally {\n      setCargando(false);\n    }\n  }, []);\n\n  useEffect(() => { cargarDatos(); }, [cargarDatos]);\n\n  const seleccionarCultivo = async (cultivo) => {\n    setCultivoActivo(cultivo);\n    // F-C01 FIX: persistir en sessionStorage para que IA y Monitoreo lo lean\n    sessionStorage.setItem("gv_cultivo_id",     String(cultivo.id_cultivo));\n    sessionStorage.setItem("gv_cultivo_nombre", cultivo.nombre_cultivo);\n    const ls = await loteService.listar(cultivo.id_cultivo).catch(() => []);\n    setLotes(ls);\n  };\n\n  const guardarCultivo = async (datos) => {\n    try {\n      if (editando) {\n        await cultivoService.actualizar(editando.id_cultivo, datos);\n      } else {\n        await cultivoService.crear(datos);\n      }\n      setModalCultivo(false);\n      setEditando(null);\n      cargarDatos();\n    } catch (e) {\n      setError(e.message);\n    }\n  };\n\n  const guardarLote = async (datos) => {\n    if (!cultivoActivo) return;\n    try {\n      await loteService.crear(cultivoActivo.id_cultivo, datos);\n      setModalLote(false);\n      const ls = await loteService.listar(cultivoActivo.id_cultivo);\n      setLotes(ls);\n    } catch (e) {\n      setError(e.message);\n    }\n  };\n\n  // ==============================================================\n  // RENDER\n  // ==============================================================\n\n  if (cargando) {\n    return (\n      <div style={estilos.contenedor}>\n        <p style={{ textAlign: "center", color: COLOR.cafeCLaro, padding: "3rem" }}>\n          Cargando cultivos...\n        </p>\n      </div>\n    );\n  }\n\n  return (\n    <div style={estilos.contenedor}>\n\n      {/* Encabezado */}\n      <div style={estilos.encabezado}>\n        <div>\n          <h1 style={estilos.titulo}>☕ Mis Cultivos</h1>\n          <p style={{ margin: 0, color: "#7a5c3a" }}>Bienvenido, {nombreUsuario}</p>\n        </div>\n        <Boton onClick={() => { setEditando(null); setModalCultivo(true); }}>\n          + Nuevo Cultivo\n        </Boton>\n      </div>\n\n      {/* Error global */}\n      {error && (\n        <div style={estilos.alerta} role="alert">\n          {error}\n          <button onClick={() => setError("")} style={{ marginLeft: "1rem", cursor: "pointer" }}>\n            cerrar\n          </button>\n        </div>\n      )}\n\n      {/* Tarjetas de resumen */}\n      {resumen && (\n        <div style={estilos.gridResumen}>\n          <Tarjeta icono="🌱" titulo="Cultivos Activos"    valor={resumen.total_cultivos_activos} />\n          <Tarjeta icono="📦" titulo="Total Lotes"         valor={resumen.total_lotes} />\n          <Tarjeta icono="✅" titulo="Lotes Vendidos"      valor={resumen.lotes_vendidos}      color={COLOR.verde}   />\n          <Tarjeta icono="⚠️" titulo="Lotes con Problema" valor={resumen.lotes_con_problema}   color={COLOR.rojo}    />\n          <Tarjeta icono="🗺️" titulo="Area Total (ha)"    valor={resumen.area_total_hectareas.toFixed(1)} />\n        </div>\n      )}\n\n      {/* Cuerpo principal: lista cultivos + detalle lotes */}\n      <div style={estilos.gridPrincipal}>\n\n        {/* Lista de cultivos */}\n        <div style={estilos.panelIzq}>\n          <h3 style={estilos.subtitulo}>Cultivos registrados</h3>\n          {cultivos.length === 0 ? (\n            <p style={{ color: "#999", fontSize: "0.9rem" }}>\n              Aun no tienes cultivos registrados.\n            </p>\n          ) : (\n            cultivos.map(c => (\n              <div\n                key={c.id_cultivo}\n                onClick={() => seleccionarCultivo(c)}\n                style={{\n                  ...estilos.itemCultivo,\n                  borderColor: cultivoActivo?.id_cultivo === c.id_cultivo\n                    ? COLOR.cafe : COLOR.borde,\n                  background: cultivoActivo?.id_cultivo === c.id_cultivo\n                    ? "#f9f3ee" : "#fff",\n                }}\n              >\n                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.4rem" }}>\n                  <strong style={{ color: COLOR.cafe }}>{c.nombre_cultivo}</strong>\n                  <Badge estado={c.estado} mapa={ESTADO_CULTIVO} />\n                </div>\n                <p style={{ margin: 0, fontSize: "0.8rem", color: "#7a5c3a" }}>\n                  {c.variedad_cafe || "Variedad no especificada"} -\n                  {c.area_hectareas ? ` ${c.area_hectareas} ha` : " Area no definida"}\n                </p>\n                <p style={{ margin: "0.2rem 0 0", fontSize: "0.78rem", color: "#aaa" }}>\n                  {c.ubicacion || "Ubicacion no registrada"}\n                </p>\n              </div>\n            ))\n          )}\n        </div>\n\n        {/* Detalle de lotes del cultivo seleccionado */}\n        <div style={estilos.panelDer}>\n          {cultivoActivo ? (\n            <>\n              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>\n                <h3 style={estilos.subtitulo}>\n                  Lotes de: {cultivoActivo.nombre_cultivo}\n                </h3>\n                <Boton onClick={() => setModalLote(true)} variante="verde">\n                  + Nuevo Lote\n                </Boton>\n              </div>\n\n              {lotes.length === 0 ? (\n                <p style={{ color: "#999", fontSize: "0.9rem" }}>\n                  Este cultivo aun no tiene lotes registrados.\n                </p>\n              ) : (\n                <div style={{ display: "flex", flexDirection: "column", gap: "0.8rem" }}>\n                  {lotes.map(l => (\n                    <div key={l.id_lote} style={estilos.itemLote}>\n                      <div style={{ display: "flex", justifyContent: "space-between" }}>\n                        <strong style={{ color: COLOR.cafe }}>{l.codigo_lote}</strong>\n                        <Badge estado={l.estado_lote} mapa={ESTADO_LOTE} />\n                      </div>\n                      <div style={{ display: "flex", gap: "2rem", marginTop: "0.5rem", fontSize: "0.82rem", color: "#7a5c3a" }}>\n                        <span>\n                          Cosecha: {l.fecha_cosecha\n                            ? new Date(l.fecha_cosecha).toLocaleDateString("es-CO")\n                            : "No registrada"}\n                        </span>\n                        <span>\n                          Cantidad: {l.cantidad_kg ? `${l.cantidad_kg} kg` : "No registrada"}\n                        </span>\n                      </div>\n                      {l.codigo_qr && (\n                        <p style={{ margin: "0.4rem 0 0", fontSize: "0.75rem", color: "#aaa" }}>\n                          QR: {l.codigo_qr.substring(0, 20)}...\n                        </p>\n                      )}\n                    </div>\n                  ))}\n                </div>\n              )}\n            </>\n          ) : (\n            <div style={{ textAlign: "center", padding: "3rem", color: "#bbb" }}>\n              <p style={{ fontSize: "3rem" }}>🌿</p>\n              <p>Selecciona un cultivo para ver sus lotes</p>\n            </div>\n          )}\n        </div>\n      </div>\n\n      {/* Modal - Nuevo / Editar Cultivo */}\n      <Modal\n        abierto={modalCultivo}\n        titulo={editando ? "Editar Cultivo" : "Registrar Nuevo Cultivo"}\n        onCerrar={() => { setModalCultivo(false); setEditando(null); }}\n      >\n        <FormularioCultivo\n          inicial={editando || {}}\n          onGuardar={guardarCultivo}\n          onCancelar={() => { setModalCultivo(false); setEditando(null); }}\n        />\n      </Modal>\n\n      {/* Modal - Nuevo Lote */}\n      <Modal\n        abierto={modalLote}\n        titulo={`Registrar Lote en: ${cultivoActivo?.nombre_cultivo || ""}`}\n        onCerrar={() => setModalLote(false)}\n      >\n        <FormularioLote\n          onGuardar={guardarLote}\n          onCancelar={() => setModalLote(false)}\n        />\n      </Modal>\n    </div>\n  );\n}\n\n// ==============================================================\n// ESTILOS\n// ==============================================================\n\nconst estilos = {\n  contenedor: {\n    minHeight:  "100vh",\n    background: COLOR.gris,\n    padding:    "2rem",\n    fontFamily: "\'Segoe UI\', Roboto, sans-serif",\n    color:      COLOR.texto,\n  },\n  encabezado: {\n    display:        "flex",\n    justifyContent: "space-between",\n    alignItems:     "center",\n    marginBottom:   "1.5rem",\n  },\n  titulo: {\n    margin:     0,\n    fontSize:   "1.8rem",\n    fontWeight: 800,\n    color:      COLOR.cafe,\n  },\n  subtitulo: {\n    margin:       "0 0 1rem",\n    fontSize:     "1rem",\n    fontWeight:   700,\n    color:        COLOR.cafe,\n    borderBottom: `2px solid ${COLOR.borde}`,\n    paddingBottom: "0.5rem",\n  },\n  gridResumen: {\n    display:             "grid",\n    gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",\n    gap:                 "1rem",\n    marginBottom:        "1.5rem",\n  },\n  gridPrincipal: {\n    display:             "grid",\n    gridTemplateColumns: "320px 1fr",\n    gap:                 "1.5rem",\n    alignItems:          "start",\n  },\n  panelIzq: {\n    background:   "#fff",\n    borderRadius: "12px",\n    border:       `1px solid ${COLOR.borde}`,\n    padding:      "1.5rem",\n  },\n  panelDer: {\n    background:   "#fff",\n    borderRadius: "12px",\n    border:       `1px solid ${COLOR.borde}`,\n    padding:      "1.5rem",\n    minHeight:    "400px",\n  },\n  itemCultivo: {\n    border:       `2px solid`,\n    borderRadius: "10px",\n    padding:      "1rem",\n    cursor:       "pointer",\n    marginBottom: "0.8rem",\n    transition:   "all 0.15s",\n  },\n  itemLote: {\n    border:       `1px solid ${COLOR.borde}`,\n    borderRadius: "10px",\n    padding:      "1rem",\n    background:   "#fafafa",\n  },\n  alerta: {\n    background:   "#fff1f0",\n    border:       "1px solid #ffccc7",\n    borderRadius: "8px",\n    padding:      "0.8rem 1rem",\n    color:        "#b91c1c",\n    marginBottom: "1rem",\n    fontSize:     "0.87rem",\n  },\n};\n'

ok = err = 0
for rel_path, new_content in ARCHIVOS.items():
    dest = BASE / rel_path.replace("/", os.sep)
    dest.parent.mkdir(parents=True, exist_ok=True)
    if dest.exists():
        bak = backup_dir / rel_path.replace("/", os.sep)
        bak.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(dest, bak)
    try:
        dest.write_text(new_content, encoding="utf-8")
        print(f"  OK {rel_path}")
        ok += 1
    except Exception as e:
        print(f"  ERROR {rel_path}: {e}")
        err += 1

# N-003 FIX: mover archivos con syntax error a docs/
print()
ia_root = BASE / "Backend" / "ia"
