docs_dir.mkdir(exist_ok=True)

n003_files = {
    "disease_prediction_pipeline.py": "disease_prediction_pipeline_TEMPLATE.py",
    "coffee_disease_model.py":        "coffee_disease_model_TEMPLATE.py",
}
